python3 - <<'PY'
from pathlib import Path
root=Path('shaders/escape_time_family/families/buffalo')
for path in sorted(root.glob('*.frag')):
    text=path.read_text()
    # print filename, first comment lines and whether Julia/fixed seed indicators appear
    markers=[]
    if 'Julia' in text or 'julia' in path.name:
        markers.append('julia')
    if 'seed' in text.lower() or 'uTime' in text:
        markers.append('seed/time')
    if 'vec2 c =' in text or 'c =' in text:
        markers.append('c')
    print(path.name, '|', ','.join(markers) or '-')
    for line in text.splitlines()[:14]:
        if line.startswith('//'):
            print(' ', line[:120])
    print()
